CREATE TABLE "BILLING_CYCLE_CONTROL" ("REGION" NUMBER(5,0), "CYCLEID" NUMBER(8,0), "MODIFYTIME" DATE DEFAULT sysdate, "OPENDAY" NUMBER(2,0) DEFAULT 0, "OFFSET_SECOND" NUMBER(6,0) DEFAULT 0) ;

