CREATE TABLE "BUFSUBSEXTENT" ("BUFID" NUMBER(8,0), "MINSUBSID" NUMBER(15,0), "MAXSUBSID" NUMBER(15,0), "SUBSCOUNT" NUMBER(10,0)) ;

