CREATE TABLE "CECONFILEINFO" ("TASK_ID" NUMBER(10,0), "TASK_NOTE" VARCHAR2(128), "CEID" NUMBER(10,0), "CONFILECATA" VARCHAR2(128), "CONFILENAME" VARCHAR2(32), "LOGFILECATA" VARCHAR2(128), "LOGFILENAMEEXP" VARCHAR2(32), "BACKUPCATA" VARCHAR2(128), "CONFIGFILE_TYPE" VARCHAR2(32), "TEST_COMMAND" VARCHAR2(128), "COMMAND_RETURN_STRING" VARCHAR2(256)) ;

